      \u0275\u0275elementStart(129, "div")(130, "h3", 33);
      \u0275\u0275text(131, "Your team ships internal tooling faster.");
      \u0275\u0275elementEnd();
      \u0275\u0275elementStart(132, "p", 34);
      \u0275\u0275text(133, " I can scope, architect, and build a production-grade internal tool in weeks. Faster feedback loops, earlier adoption, and less time sunk on tools nobody ends up using. ");
      \u0275\u0275elementEnd()()();
      \u0275\u0275elementStart(134, "div", 35)(135, "div", 32);
      \u0275\u0275text(136, "\u2192");
      \u0275\u0275elementEnd();
      \u0275\u0275elementStart(137, "div")(138, "h3", 33);
      \u0275\u0275text(139, "Your stakeholders get answers without opening a ticket.");
      \u0275\u0275elementEnd();
      \u0275\u0275elementStart(140, "p", 34);
      \u0275\u0275text(141, " Self-service dashboards, automated reports, and well-structured APIs mean your data team stops being a request queue. Stakeholders pull what they need. The bottleneck disappears. ");
      \u0275\u0275elementEnd()()();
      \u0275\u0275elementStart(142, "div", 31)(143, "div", 32);
      \u0275\u0275text(144, "\u2192");
      \u0275\u0275elementEnd();
      \u0275\u0275elementStart(145, "div")(146, "h3", 33);
      \u0275\u0275text(147, "Your systems are observable from day one.");
      \u0275\u0275elementEnd();
      \u0275\u0275elementStart(148, "p", 34);
      \u0275\u0275text(149, " I don't ship without monitoring. Prometheus, Grafana, health endpoints, and structured logging mean you know what's happening in your infrastructure before something breaks. ");
